var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"로웰 양이라고 했지.","JPN":"ローウェル君と言ったな。","ENG":"Lowell, was it?","TWN":"你叫勞威爾對吧？"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"떠나기 전에 잠시 이야기를 나눌 수 있을까?","JPN":"戻る前に、少し話せるかね？","ENG":"Could I have a word with you before you go?","TWN":"離開前可以聊幾句嗎？"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……당신은?","JPN":"……あなたは？","ENG":"...You're?","TWN":"……你是？"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"클리포트 게임에서 봤던 기억이 있습니다. 분명…….","JPN":"クリフォトゲームでお会いしましたよね。確か……","ENG":"I remember seeing you at the Qliphoth Game. You're the...","TWN":"我記得在逆卡巴拉遊戲中有見過你，你是……"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"지금은 그냥 코치일 뿐이라네.","JPN":"今はただのコーチだ。","ENG":"Right now, I'm just a coach.","TWN":"我現在就只是一名教練。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"코치라고요……?","JPN":"コーチですか……？","ENG":"A coach...?","TWN":"教練嗎……？"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"어쩌면 저희가 이번 리그를 너무 쉽게 생각했던 걸지도 모르겠군요.","JPN":"もしかすると私たちは今回のリーグを甘く見すぎていたのかもしれませんね。","ENG":"Perhaps we underestimated this year's league.","TWN":"或許我們把這次的聯賽看得太簡單了。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아니, 자네들은 무척 힘든 상대였다네.","JPN":"いや、君たちはとても手強かった。","ENG":"No, your team was a formidable opponent.","TWN":"不，你們是相當可敬的對手。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가 마지막에 승부를 포기하지 않았다면, 어느 한 쪽이 크게 다치고 말았을 거야.","JPN":"君が最後に勝負を諦めてくれなかったら、どちらかが酷い怪我を負うことになっただろう。","ENG":"If you hadn't given up at the last second, either side would have suffered serious injuries.","TWN":"要是你最後一刻沒有放棄奪勝，結果很可能就是兩敗俱傷。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"아니요. 그건 명백히 제 실책입니다.","JPN":"いいえ。あれは完全に私の失策でした。","ENG":"No. That was clearly my mistake.","TWN":"不，那是我個人的失誤。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"잠깐의 승부욕 때문에 기사로서 넘어서는 안 되는 선을 넘을 뻔했으니까요.","JPN":"一時の負けたくないという気持ちに屈し、騎士として越えてはならない一線を越えるところでしたから。","ENG":"I was blinded by victory and almost crossed a line that no knight should.","TWN":"我暫時被勝負給蒙蔽雙眼，差點越過那條騎士不該越過的線。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"단련이 부족한 탓이겠죠. 반성하고 있습니다.","JPN":"鍛錬が足りないせいでしょうね。反省しております。","ENG":"It is my lack of training. I must reflect on my actions.","TWN":"都怪我的訓練還不夠成熟，我會好好反省的。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 겸손하군.","JPN":"はは、謙遜だな。","ENG":"Ha ha, how modest of you.","TWN":"哈哈，你真是謙卑。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"실은 조디악 나이츠에 대해 몇 가지 듣고 싶네만, 괜찮겠나?","JPN":"実はゾディアックナイツについていくつか聞きたいのだが、構わないかね？","ENG":"Actually, I wanted to ask you a few questions about the Zodiac Knights. Is that all right with you?","TWN":"我有些十二宮騎士團的事想問你，不知道方便嗎？"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"기사단의 내부 사정을 외부에 발설하는 건, 그다지 바람직하지 못한 행동이지만…….","JPN":"騎士団内部の事情を外部に洩らすことは、あんまり望ましくない行動ですが……","ENG":"Talking about the order's internal affairs to an outsider may not be such a good idea, but...","TWN":"基本上騎士團內部的事情是不能對外透露的……"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"좋습니다. 당신이라면 신뢰할 수 있겠죠.","JPN":"いいでしょう。あなたなら信用できます。","ENG":"Very well. I believe you can be trusted.","TWN":"不過好吧！我想你是信得過的！"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};